import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AddEmployee.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams(); // If id exists -> Edit Mode

  const [employee, setEmployee] = useState({
    name: "",
    empId: "",
    email: "",
    dob: "",
    gender: "",
    maritalStatus: "",
    designation: "",
    department: "",
    salary: "",
    role: "Employee",

    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: ""
  });

  // Load employee in EDIT mode
  useEffect(() => {
    if (!id) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find(emp => emp.id === id);

    if (found) setEmployee(found);
  }, [id]);

  const handleChange = (e) => {
    setEmployee({ ...employee, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    if (id) {
      employees = employees.map(emp => emp.id === id ? { ...employee } : emp);
      alert("Employee Updated Successfully!");
    } else {
      employees.push({ ...employee, id: Date.now().toString() });
      alert("Employee Added Successfully!");
    }

    localStorage.setItem("employees", JSON.stringify(employees));
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">
      <h2>{id ? "Edit Employee" : "Add Employee"}</h2>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* PERSONAL DETAILS */}
        <h3>Personal Details</h3>
        <div className="employee-grid">

          <input name="name" value={employee.name} onChange={handleChange} placeholder="Name" />
          <input name="empId" value={employee.empId} onChange={handleChange} placeholder="Employee ID" />

          <input name="email" value={employee.email} onChange={handleChange} placeholder="Email" />
          <input type="date" name="dob" value={employee.dob} onChange={handleChange} />

          <select name="gender" value={employee.gender} onChange={handleChange}>
            <option value="">Select Gender</option>
            <option>Male</option>
            <option>Female</option>
          </select>

          <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
            <option value="">Select Marital Status</option>
            <option>Single</option>
            <option>Married</option>
          </select>

        </div>


        {/* JOB DETAILS */}
        <h3>Job Details</h3>
        <div className="employee-grid">

          <input name="designation" value={employee.designation} onChange={handleChange} placeholder="Designation" />
          <input name="department" value={employee.department} onChange={handleChange} placeholder="Department" />
          <input name="salary" value={employee.salary} onChange={handleChange} placeholder="Salary" />

          <select name="role" value={employee.role} onChange={handleChange}>
            <option>Employee</option>
            <option>Admin</option>
          </select>

        </div>


        {/* BANK DETAILS */}
        <h3>Bank Details</h3>
        <div className="employee-grid">

          <input name="bankName" value={employee.bankName} onChange={handleChange} placeholder="Bank Name" />
          <input name="accountNumber" value={employee.accountNumber} onChange={handleChange} placeholder="Account Number" />
          <input name="ifsc" value={employee.ifsc} onChange={handleChange} placeholder="IFSC Code" />

        </div>


        {/* EDUCATIONAL DETAILS */}
        <h3>Educational Details</h3>
        <div className="employee-grid">

          <input name="qualification" value={employee.qualification} onChange={handleChange} placeholder="Highest Qualification" />
          <input name="university" value={employee.university} onChange={handleChange} placeholder="University" />
          <input name="passingYear" value={employee.passingYear} onChange={handleChange} placeholder="Passing Year" />

        </div>

        <button type="submit" className="submit-btn">
          {id ? "Update Employee" : "Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
